#include <stdio.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        long long X, Y; scanf("%lld %lld", &X, &Y);
        long long W = X > Y ? X : Y;
        long long S = X + Y;
        long long oddS = (S % 2 == 1) ? S : S + 1;
        long long N = oddS > (2*W - 1) ? oddS : (2*W - 1);
        printf("%lld\n", N);
    }
    return 0;
}

